// Ambil data jam dari Get Jam dari Sheet (bukan dari input langsung)
let row = {};
try {
  const jamRows = $('Get Jam dari Sheet').all().map(i => i.json);
  row = jamRows.find(r => String(r.key || '').trim() === 'jam_absen_global')
     || jamRows[0]
     || {};
} catch(_) {}

// Ambil daftar admin dari Get Admin List
let adminIds = [];
let adminRoles = {};
try {
  const adminRows = $('Get Admin List').all().map(i => i.json);
  adminRows.forEach(r => {
    // PERBAIKAN: Gunakan String, JANGAN gunakan parseInt agar tidak dibulatkan
    const uid = String(r.NIP || r.nip || '').trim();
    if (uid && uid !== '0') {
      adminIds.push(uid);
      // Normalisasi role: jika mengandung 'super', paksa jadi 'superadmin'
      let role = String(r.role || 'admin').toLowerCase().trim();
      if (role.indexOf('super') !== -1) role = 'superadmin'; // Preserve roles like kepala, kabid
      adminRoles[uid] = role;
    }
  });
} catch(_) {}

return [{ json: {
  ok: true,
  data: {
    masuk:      row.masuk      || '07:15',
    pulang:     row.pulang     || '14:30',
    updated_at: row.updated_at || null,
    admin_ids:  adminIds,
    admin_roles: adminRoles
  }
}}];

