const saved    = $input.first().json;
const body     = $('Absen').first().json.body || {};
const validasi = $('Validasi Absen').first().json;
const pgw      = $('Get Pegawai Absen').first().json;

const nama      = validasi.pegawai?.nama    || pgw.username || pgw.Nama || '—';
const nip       = validasi.pegawai?.nip     || pgw.NIP      || '—';
const tanggal   = validasi.log?.tanggal     || body.tanggal_iso || saved.Tanggal || '—';
const jamRaw    = validasi.log?.jam         || body.jam         || saved.Jam     || '—';
const lokasi    = validasi.nama_lokasi      || saved.Lokasi     || '—';
const jenisAbsen= validasi.jenis_absen      || saved['Jenis Absen'] || '—';
const chatId    = String(body.user?.id || body.ID || $input.first().json.ID || '1383864355');
const periodeAktif = validasi.periode_aktif || null;

// ==========================================
// LOGIKA FORMAT NOMOR HP UNTUK WAHA
// ==========================================
const nomorHpRaw = validasi.pegawai?.nomorhp || pgw.nomorhp || pgw.NomorHP || '';
let wahaChatId = '';

if (nomorHpRaw) {
  let cleanHp = String(nomorHpRaw).replace(/\D/g, ''); // Hapus karakter selain angka (spasi, strip, dll)
  if (cleanHp.startsWith('0')) {
    cleanHp = '62' + cleanHp.substring(1); // Ubah awalan 0 menjadi 62
  }
  wahaChatId = cleanHp + '@c.us'; // Format standar chat personal untuk WAHA
}
// ==========================================

const jamBersih = jamRaw.replace(/\s*WITA\s*/gi, '').trim().slice(0,5);

// Hitung info terlambat/lebih awal
function parseHHMM(s) {
  const m = String(s || '').match(/(\d{1,2}):(\d{2})/);
  if (!m) return null;
  return parseInt(m[1]) * 60 + parseInt(m[2]);
}

// Ambil jam batas dari Validasi (via Get Jam Absen + Get Periode Absen)
let jamAbsenRow = {};
try {
  const jamRows = $('Get Jam Absen').all().map(i => i.json);
  jamAbsenRow = jamRows.find(r => r.key === 'jam_absen_global') || jamRows[0] || {};
} catch(_) {}

let BATAS_MASUK_STR  = jamAbsenRow.masuk  || '08:00';
let BATAS_PULANG_STR = jamAbsenRow.pulang || '14:30';
let sumberJam = 'Global';

// Cek periode aktif
try {
  const periodeRows = $('Get Periode Absen').all().map(i => i.json);
  for (const row of periodeRows) {
    const dari   = String(row.dari   || '').trim();
    const sampai = String(row.sampai || dari).trim();
    const masuk  = String(row.masuk  || '').trim();
    const pulang = String(row.pulang || '').trim();
    const nama_p = String(row.nama   || '').trim();
    if (!dari || !masuk || !pulang) continue;
    if (tanggal >= dari && tanggal <= sampai) {
      BATAS_MASUK_STR  = masuk;
      BATAS_PULANG_STR = pulang;
      sumberJam = nama_p || 'Periode Khusus';
      break;
    }
  }
} catch(_) {}

const BATAS_MASUK  = parseHHMM(BATAS_MASUK_STR);
const BATAS_PULANG = parseHHMM(BATAS_PULANG_STR);
const mJam = parseHHMM(jamBersih);

// Hitung keterlambatan / pulang lebih awal
let infoWaktu = '';
if (jenisAbsen === 'DI LUAR JAM MASUK' && mJam !== null && BATAS_MASUK !== null) {
  const telat = mJam - BATAS_MASUK;
  const j = Math.floor(telat / 60), m = telat % 60;
  infoWaktu = j > 0 ? `⏰ Terlambat ${j} jam ${m} menit` : `⏰ Terlambat ${m} menit`;
} else if (jenisAbsen === 'DI LUAR JAM PULANG' && mJam !== null && BATAS_PULANG !== null) {
  const cepat = BATAS_PULANG - mJam;
  const j = Math.floor(cepat / 60), m = cepat % 60;
  infoWaktu = j > 0 ? `⚠️ Pulang lebih awal ${j} jam ${m} menit` : `⚠️ Pulang lebih awal ${m} menit`;
}

const jenisDisplay =
  jenisAbsen === 'DI LUAR JAM MASUK'  ? '⏰ TERLAMBAT' :
  jenisAbsen === 'DI LUAR JAM PULANG' ? '⚠️ Pulang Lebih Awal' :
  jenisAbsen === 'PULANG LUAR'        ? '🏃 Pulang dari Lapangan' :
  jenisAbsen === 'MASUK'              ? '✅ Masuk Tepat Waktu' :
  jenisAbsen === 'PULANG'             ? '🔵 Pulang Tepat Waktu' :
  jenisAbsen;

const jamBatasInfo = `⏳ Batas: Masuk ≤${BATAS_MASUK_STR} | Pulang ≥${BATAS_PULANG_STR}${periodeAktif ? ' ('+periodeAktif+')' : ' (Global)'}`;

const text =
  `✅ *KONFIRMASI ABSENSI BERHASIL*\n` +
  `Halo, *${nama}*!\n\n` +
  `📌 *Jenis* : ${jenisDisplay}\n` +
  (infoWaktu ? `${infoWaktu}\n` : '') +
  `👤 *NIP*   : ${nip}\n` +
  `📍 *Lokasi*: ${lokasi}\n` +
  `📅 *Tgl*   : ${tanggal}\n` +
  `🕒 *Waktu* : ${jamBersih} WITA\n` +
  `${jamBatasInfo}\n\n` +
  `Terima kasih, selamat melanjutkan aktivitas!`;

// Note: Output sekarang melempar 3 data (chat_id Telegram, waha_chat_id WA, dan text)
return [{ json: { chat_id: chatId, waha_chat_id: wahaChatId, text } }];

