const body      = $('Absen').first().json.body || {};
const user      = body.user        || {};
const lat       = parseFloat(body.latitude);
const lng       = parseFloat(body.longitude);

const accuracy  = parseFloat(body.horizontal_accuracy) || parseFloat(body.accuracy) || 0;

const rawId     = user.id || body.telegram_id;
const tgId      = rawId ? String(rawId) : null;
const isMejaAbsen = body.source === 'meja_absen';
// SECRET TOKEN UNTUK MEJA ABSEN (Bisa disesuaikan dengan frontend di config.js)
const validMejaToken = body.meja_token === 'BAPPERIDA_MEJA_SECURE_2026';

const tanggalIso= body.tanggal_iso || '';
const jamStr    = body.jam         || '';
const gpsFp     = body.gps_fingerprint || {};

const pegawaiItems = $('Get Pegawai Absen').all();
const pegawai = pegawaiItems.length ? pegawaiItems[0].json : null;
const lokasiItems = $('Get Lokasi').all().map(i => i.json);
const absenHariIni = $('Get Absen Masuk').all().map(i => i.json);

// ── Baca jam global dari datatable ──
const jamAbsenRows = $('Get Jam Absen').all().map(i => i.json);
const jamAbsenRow  = jamAbsenRows.find(r => r.key === 'jam_absen_global') || {};

function parseHHMM(s) {
  const m = String(s || '').match(/(\d{1,2}):(\d{2})/);
  if (!m) return null;
  return parseInt(m[1]) * 60 + parseInt(m[2]);
}

const JAM_MASUK_GLOBAL  = parseHHMM(jamAbsenRow.masuk)  ?? 8  * 60;
const JAM_PULANG_GLOBAL = parseHHMM(jamAbsenRow.pulang) ?? 14 * 60 + 30;

// ── Cek jam_periode aktif untuk tanggal absen ──
let BATAS_MASUK  = JAM_MASUK_GLOBAL;
let BATAS_PULANG = JAM_PULANG_GLOBAL;
let namaPeriodeAktif = null;

try {
  const periodeRows = $('Get Periode Absen').all().map(i => i.json);
  for (const row of periodeRows) {
    const dari   = String(row.dari   || row.Dari   || '').trim();
    const sampai = String(row.sampai || row.Sampai || row.sampai_tanggal || '').trim();
    const masuk  = String(row.masuk  || row.Masuk  || '').trim();
    const pulang = String(row.pulang || row.Pulang || '').trim();
    const nama   = String(row.nama   || row.Nama   || '').trim();
    if (!dari || !masuk || !pulang) continue;
    const s = sampai || dari;
    if (tanggalIso >= dari && tanggalIso <= s) {
      const jm = parseHHMM(masuk);
      const jp = parseHHMM(pulang);
      if (jm !== null && jp !== null) {
        BATAS_MASUK  = jm;
        BATAS_PULANG = jp;
        namaPeriodeAktif = nama;
        break;
      }
    }
  }
} catch(_) {}

const TENGAH_HARI = 12 * 60;

// ─── Fungsi bantu ─────────────────────────────────────────────
function tolak(kode, pesan) {
  return [{ json: { is_valid: false, kode_tolak: kode, keterangan: pesan, data_input: { tgId, lat, lng, accuracy, tanggalIso, jamStr } }}];
}

function terima(jenis, lokasiNama, ketLog = '-') {
  return [{ json: {
    is_valid: true, jenis_absen: jenis, nama_lokasi: lokasiNama,
    periode_aktif: namaPeriodeAktif,
    keterangan: `${jenis} berhasil dicatat di ${lokasiNama}${namaPeriodeAktif ? ' ('+namaPeriodeAktif+')' : ''}`,
    keterangan_log: ketLog,
    pegawai: { id: tgId, nama: pegawai?.nama || pegawai?.Nama || pegawai?.username || '', nip: pegawai?.NIP || pegawai?.nip || '', jabatan: pegawai?.Jabatan || pegawai?.jabatan || '', nomorhp: pegawai?.nomorhp || pegawai?.NomorHP || '', instansi_id: pegawai?.instansi_id || pegawai?.Instansi_ID || '' },
    log: { tanggal: tanggalIso, jam: jamStr.split(' ')[0], koordinat: `${lat},${lng}`, akurasi: accuracy }
  }}];
}

function haversine(lat1, lng1, lat2, lng2) {
  const R = 6371000;
  const dL = (lat2-lat1)*Math.PI/180, dG = (lng2-lng1)*Math.PI/180;
  const a = Math.sin(dL/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dG/2)**2;
  return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));
}

function parseJamWITA(str) {
  const m = String(str).match(/(\d{1,2}):(\d{2})/);
  if (!m) return null;
  return { h: parseInt(m[1]), m: parseInt(m[2]) };
}

function ipToInt(ip) {
  return ip.trim().split('.').reduce((acc, octet) => {
    const n = parseInt(octet, 10);
    if (isNaN(n) || n < 0 || n > 255) throw new Error('Oktet IP tidak valid: ' + ip);
    return (acc << 8) | n;
  }, 0) >>> 0;
}

function ipInCIDR(ip, cidr) {
  try {
    cidr = cidr.trim();
    if (!cidr.includes('/')) return ip.trim() === cidr;
    const [range, prefixStr] = cidr.split('/');
    const prefix = parseInt(prefixStr, 10);
    if (isNaN(prefix) || prefix < 0 || prefix > 32) return false;
    const mask = prefix === 0 ? 0 : (~((1 << (32 - prefix)) - 1)) >>> 0;
    return (ipToInt(ip) & mask) === (ipToInt(range) & mask);
  } catch (_) {
    return false;
  }
}

// ─── Dapatkan nama hari ini ───────────────────────────────────
function getHariIni() {
  const hariIndo = ['minggu', 'senin', 'selasa', 'rabu', 'kamis', 'jumat', 'sabtu'];
  let dateObj;
  if (tanggalIso) {
    dateObj = new Date(tanggalIso + 'T00:00:00+08:00');
    if (isNaN(dateObj.getTime())) dateObj = new Date();
  } else {
    dateObj = new Date();
  }
  try {
    const formatter = new Intl.DateTimeFormat('id-ID', { weekday: 'long', timeZone: 'Asia/Makassar' });
    const hariStr = formatter.format(dateObj).toLowerCase();
    if (hariIndo.includes(hariStr)) return hariStr;
  } catch (_) {}
  const witaTime = dateObj.getTime() + (dateObj.getTimezoneOffset() * 60000) + (8 * 3600000);
  const witaDate = new Date(witaTime);
  return hariIndo[witaDate.getDay()];
}

const hariIni = getHariIni();

const netInfo   = body.network_info || {};
const rawHeader = $('Absen').first().json.headers?.['x-forwarded-for'] || '';
const headerIP  = rawHeader.split(',')[0].trim();
const realIP    = $('Absen').first().json.headers?.['x-real-ip'] || '';
const ipCek     = headerIP || realIP || netInfo.ip_public || '';

// ── Validasi Keamanan Tambahan ──
if (isMejaAbsen && !validMejaToken) {
  return tolak('MEJA_TOKEN_INVALID', 'Akses Meja Absen ditolak (Token tidak valid/tidak ditemukan).');
}

// ── Validasi GPS ──
if (!isMejaAbsen) {
  if (isNaN(accuracy) || accuracy <= 0) return tolak('GPS_ACCURACY_ZERO', 'Akurasi GPS tidak valid. Nonaktifkan Fake GPS.');
  if (accuracy > 500) return tolak('GPS_WEAK', `Sinyal GPS lemah (${Math.round(accuracy)}m). Coba di area terbuka.`);
  const adaAltitude = gpsFp.has_altitude === true;
  if (accuracy < 3 && !adaAltitude) return tolak('GPS_ACCURACY_TOO_PERFECT', `Akurasi ${accuracy.toFixed(1)}m terlalu sempurna tanpa data altitude.`);
  if (gpsFp && typeof gpsFp === 'object') {
    const nullCount = [gpsFp.has_altitude===false,gpsFp.has_altitude_acc===false,gpsFp.has_heading===false,gpsFp.has_speed===false].filter(Boolean).length;
    if (nullCount >= 4 && accuracy <= 10) return tolak('GPS_FAKE_FINGERPRINT', 'Profil data GPS tidak lengkap. Nonaktifkan Fake GPS.');
  }
}

// ── Validasi pegawai ──
if (!pegawai) return tolak('PEGAWAI_TIDAK_DITEMUKAN', 'ID Telegram tidak terdaftar di sistem. Hubungi admin.');
const status = String(pegawai.Status || pegawai.status || 'AKTIF').toUpperCase();
if (status === 'NONAKTIF' || status === 'INACTIVE') return tolak('PEGAWAI_NONAKTIF', 'Akun pegawai ini dinonaktifkan.');

if (isNaN(lat) || isNaN(lng)) return tolak('KOORDINAT_INVALID', 'Koordinat GPS tidak valid.');
if (lat === 0 && lng === 0) return tolak('KOORDINAT_NULL', 'Koordinat GPS 0,0 tidak valid.');

// ── Validasi jam & jenis absen ──
const jam = parseJamWITA(jamStr);
if (!jam) return tolak('JAM_INVALID', 'Format jam tidak valid.');
const totalMenit = jam.h * 60 + jam.m;

let jenisAbsen;
if      (totalMenit <= BATAS_MASUK)  jenisAbsen = 'MASUK';
else if (totalMenit <= TENGAH_HARI)  jenisAbsen = 'DI LUAR JAM MASUK';
else if (totalMenit <  BATAS_PULANG) jenisAbsen = 'DI LUAR JAM PULANG';
else                                 jenisAbsen = 'PULANG';

// Jika frontend menyatakan ini PULANG LUAR
if (body.jenis_absen === 'PULANG LUAR' && body.skip_radius_check === true) jenisAbsen = 'PULANG LUAR';

// ────────────────────────────────────────────────────────
// ✅ CEK DUPLIKASI & STATUS (DIPINDAH KE ATAS)
// ────────────────────────────────────────────────────────
const GRP_MASUK  = ['MASUK','DI LUAR JAM MASUK'];
const GRP_PULANG = ['PULANG','DI LUAR JAM PULANG','PULANG LUAR'];
const GRP_KET    = ['IZIN','SAKIT','TUGAS','DL','TUBEL','CUTI','TB','TANPA BERITA','ALPA'];

const absenHariIniFiltered = absenHariIni.filter(r => {
  const rTgl = String(r['Tanggal']||r.tanggal||'').trim();
  const rId  = String(r['ID']||r.id||'').trim();
  return rTgl === tanggalIso && rId === String(tgId);
});

const jamSubmit = parseHHMM(jamStr);
const duplikat = absenHariIniFiltered.some(r => {
  const jamLog = parseHHMM(String(r['Jam']||r.jam||''));
  if (jamLog === null || jamSubmit === null) return false;
  return Math.abs(jamLog - jamSubmit) <= 1;
});
if (duplikat) return tolak('DUPLIKAT_ABSEN', 'Permintaan absen duplikat. Silakan tunggu sebentar.');

const sudahKetLog = absenHariIniFiltered.find(r => GRP_KET.includes(String(r['Jenis Absen']||r.jenis||'').toUpperCase().trim()));
if (sudahKetLog) {
  const jenisKet = String(sudahKetLog['Jenis Absen']||sudahKetLog.jenis||'KETERANGAN').toUpperCase();
  return tolak('SUDAH_ADA_KETERANGAN', `Anda tidak bisa melakukan absen karena sudah tercatat memiliki keterangan: ${jenisKet}`);
}

const sudahMasuk  = absenHariIniFiltered.some(r => GRP_MASUK.includes(String(r['Jenis Absen']||r.jenis||'').toUpperCase().trim()));
const sudahPulang = absenHariIniFiltered.some(r => GRP_PULANG.includes(String(r['Jenis Absen']||r.jenis||'').toUpperCase().trim()));

if (GRP_MASUK.includes(jenisAbsen)  && sudahMasuk)  return tolak('SUDAH_ABSEN', 'Pegawai sudah melakukan absen masuk hari ini.');
if (GRP_PULANG.includes(jenisAbsen) && sudahPulang) return tolak('SUDAH_ABSEN', 'Pegawai sudah melakukan absen pulang hari ini.');

const isPulang = ['PULANG','DI LUAR JAM PULANG','PULANG LUAR'].includes(jenisAbsen);
const adaMasuk = absenHariIniFiltered.some(r => { const j=String(r['Jenis Absen']||r.jenis||'').toUpperCase().trim(); return j==='MASUK'||j==='DI LUAR JAM MASUK'; });
if (isPulang && !adaMasuk) return tolak('BELUM_MASUK', 'Pegawai belum melakukan absen masuk hari ini.');

// Jika lulus semua cek di atas dan jenisnya PULANG LUAR, maka otomatis lolos (tanpa cek GPS kantor)
if (jenisAbsen === 'PULANG LUAR') {
  return terima('PULANG LUAR', 'Lapangan', body.keterangan || 'Pulang dari lapangan');
}

// ────────────────────────────────────────────────────────
// ✅ Validasi lokasi (dengan pengecualian WFH / Meja)
// ────────────────────────────────────────────────────────
let lokasiValid   = null;
let ketLog        = '-';

if (isMejaAbsen) {
  lokasiValid = body.lokasi_nama || 'Meja Absen';
} else {
  if (!lokasiItems.length) {
    return tolak('NO_LOKASI', 'Tidak ada data lokasi kantor. Hubungi admin.');
  }

  const accuracyBuffer = Math.min(accuracy, 50);
  let lokasiIPGagal = null;
  let ipMissing = false;

  for (const lok of lokasiItems) {
    const namaLok = lok.Nama_Lokasi || lok.nama_lokasi || 'Kantor';
    const isWFH = (namaLok.toUpperCase() === 'WFH');
    const jarak = haversine(lat, lng, parseFloat(lok.latitude), parseFloat(lok.longitude));

    // 1. Cek hari (wajib untuk semua lokasi, termasuk WFH)
    const hariStr = String(lok.hari || '').toLowerCase();
    if (!hariStr) continue; // If no days are assigned, skip this location
    if (hariStr) {
      const hariList = hariStr.split(',').map(h => h.trim());
      if (!hariList.includes(hariIni)) continue;
    }

    // 2. Jika BUKAN WFH → cek radius
    if (!isWFH) {
      if (jarak > (parseFloat(lok.radius) || 100) + accuracyBuffer) continue;

      // 3. Jika BUKAN WFH dan IP diatur → cek IP
      const ipRangeRaw = String(lok.ip_range || '').trim();
      if (ipRangeRaw) {
        if (!ipCek) {
          lokasiIPGagal = namaLok;
          ipMissing = true;
          continue;
        }
        const rangeList = ipRangeRaw.split(',').map(s => s.trim()).filter(Boolean);
        if (!rangeList.some(cidr => ipInCIDR(ipCek, cidr))) {
          lokasiIPGagal = lokasiIPGagal || namaLok;
          continue;
        }
      }
    }

    // Lolos semua filter (hari, dan jika bukan WFH: radius+IP)
    lokasiValid = namaLok;
    break;
  }

  if (!lokasiValid) {
    let alasan = '';
    if (lokasiIPGagal) {
      alasan = ipMissing 
        ? `Anda berada di area ${lokasiIPGagal} tetapi tidak terhubung ke WiFi kantor.`
        : `IP Anda bukan jaringan kantor di area ${lokasiIPGagal}.`;
    } else {
      const isWeekend = (hariIni === 'sabtu' || hariIni === 'minggu');
      const adaLokasiHariIni = lokasiItems.some(lok => {
        const hariStr = String(lok.hari || '').toLowerCase();
        if (!hariStr) return true;
        return hariStr.split(',').map(h => h.trim()).includes(hariIni);
      });
      if (isWeekend && !adaLokasiHariIni) {
        alasan = `Hari ${hariIni} adalah hari libur. Tidak ada lokasi absen yang tersedia.`;
      } else {
        alasan = `Lokasi Anda tidak sesuai dengan hari ${hariIni} atau di luar radius semua kantor.`;
      }
    }
    return tolak('LOKASI_TIDAK_VALID', alasan);
  }

  // Keterangan tambahan jika WFH atau akhir pekan
  if (lokasiValid.toUpperCase() === 'WFH') {
    ketLog = `WFH (${hariIni})`;
  } else if (hariIni === 'sabtu' || hariIni === 'minggu') {
    ketLog = `Absen akhir pekan (${hariIni}) di ${lokasiValid}`;
  }
}

return terima(jenisAbsen, lokasiValid, ketLog);

