    nomorhp: clean(body.no_hp || body.nomorhp || body.NomorHP),
    instansi_id: clean(body.instansi_id || '')
  } 
}];

const allPegawai = $input.all().map(i => i.json);

// Scoring Functions (Hierarki)
function getJabatanScore(j) {
  if (!j) return 0;
  const s = String(j).toUpperCase().trim();
  if (s.includes('KEPALA DINAS') || s.includes('KEPALA BADAN') || s.includes('INSPEKTUR') || s === 'KEPALA') return 100;
  if (s.includes('SEKRETARIS')) return 90;
  if (s.includes('KEPALA BIDANG') || s.includes('KABID') || s.includes('IRBAN')) return 80;
  if (s.includes('KASUBAG') || s.includes('KASUBBID') || s.includes('KETUA TIM') || s.includes('KOORDINATOR')) return 70;
  if (s.includes('NON ASN') || s.includes('HONORER') || s.includes('THL')) return 40;
  return 50; // Staf/Pelaksana
}

function getPangkatScore(p) {
  if (!p) return 0;
  const s = String(p).toUpperCase().replace(/\s/g, '').replace(/[.-]/g, '/');
  if (s.includes('IV/E')) return 17;
  if (s.includes('IV/D')) return 16;
  if (s.includes('IV/C')) return 15;
  if (s.includes('IV/B')) return 14;
  if (s.includes('IV/A')) return 13;
  if (s.includes('III/D')) return 12;
  if (s.includes('III/C')) return 11;
  if (s.includes('III/B')) return 10;
  if (s.includes('III/A')) return 9;
  if (s.includes('II/D')) return 8;
  if (s.includes('II/C')) return 7;
  if (s.includes('II/B')) return 6;
  if (s.includes('II/A')) return 5;
  if (s.includes('I/D')) return 4;
  if (s.includes('I/C')) return 3;
  if (s.includes('I/B')) return 2;
  if (s.includes('I/A')) return 1;
  return 0;
}

function getUmurScore(nip) {
  const dob = String(nip || '99999999').replace(/\D/g, '').substring(0, 8);
  return dob.length === 8 ? parseInt(dob) : 99999999;
}

// 1. Sortir Berdasarkan Hierarki
const list = [...allPegawai];
list.sort((a, b) => {
  const scoreJa = getJabatanScore(a.Jabatan || a.jabatan);
  const scoreJb = getJabatanScore(b.Jabatan || b.jabatan);
  if (scoreJa !== scoreJb) return scoreJb - scoreJa;

  const scorePa = getPangkatScore(a.pangkat || a.Pangkat);
  const scorePb = getPangkatScore(b.pangkat || b.Pangkat);
  if (scorePa !== scorePb) return scorePb - scorePa;

  const ageA = getUmurScore(a.NIP || a.nip);
  const ageB = getUmurScore(b.NIP || b.nip);
  if (ageA !== ageB) return ageA - ageB;

  return 0;
});

// 2. Berikan Nomor Urut Baru dan Filter Perubahan (Loop Prevention)
const updates = [];
list.forEach((p, index) => {
  const newNo = index + 1;
  const oldNo = p.no ? parseInt(p.no) : null;

  if (newNo !== oldNo) {
    updates.push({
      json: {
        id: String(p.id || p.ID),
        no: newNo,
        username: p.username || p.Nama || p.nama
      }
    });
  }
});

return updates;

