    nip: clean(body.nip || body.NIP),
    jabatan: clean(body.jabatan || body.Jabatan),
    bidang: clean(body.bidang || body.Bidang),
    status: clean(body.status || body.Status || 'AKTIF').toUpperCase(),
    role: clean(body.role || body.Role || 'USER').toUpperCase(),
    pangkat: clean(body.pangkat || body.Pangkat),
    no, 
    nomorhp 
  } 
}];

const inputDate = $input.first().json.timestamp;
const dateObj = new Date(inputDate);

// Opsi untuk format lokal
const options = {
  timeZone: 'Asia/Makassar',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
};

// Mengambil string lokal secara utuh
const localString = dateObj.toLocaleString('en-GB', options);

// Memisahkan tanggal dan jam (Format en-GB: DD/MM/YYYY, HH:mm:ss)
const [datePart, timePart] = localString.split(', ');
const [day, month, year] = datePart.split('/');

// Susun ulang tanggal ke format YYYY-MM-DD agar rapi
const tanggal = `${year}-${month}-${day}`;
const jam = timePart;

return [{
  json: {
    tanggal: tanggal,
    jam: jam
  }
}];

// 1. Ambil data tanggal dan jam dari node sebelumnya
const infoTanggal = $input.first().json;

// 2. Data yang di-hardcode
const dataKaryawan = [
  {
    "idx": 18, "id": 2897, "username": "Angelina Kamila Lalo, S.Tr.I.P",
    "NIP": "200104262023082002", "Jabatan": "Fasilitator Pemerintahan",
    "Status": "TUGAS", "JenisAbsen": "TUBEL", "ket": "TUBEL", 
    "lok":"-","koordinat":"-"
  }
];

// 3. Gabungkan data karyawan dengan tanggal, lalu pecah menjadi item terpisah untuk n8n
return dataKaryawan.map(karyawan => {
  return {
    json: {
      ...karyawan,
      tanggal_input: infoTanggal.tanggal,
      jam_input: infoTanggal.jam.substring(0, 5)
    }
  };
});

const req = $input.first().json;
if (req.method === 'OPTIONS') {
  return [{ json: { _cors_preflight: true } }];
}
return [{ json: req }];

const body = $input.first().json.body || {};
const logId = body.ID_Log || body.id_log || body.ID_LOG || body.ID_log || body.Id_Log || null;
const id = String(body.telegram_id || '').trim();
const nama = String(body.nama || '').trim();
const nip = String(body.nip || '').trim();
const tgl = String(body.tanggal || '').trim();
const jam = String(body.jam || '').trim();
const jenis = String(body.jenis_absen || '').trim();
const ket = String(body.keterangan || '').trim();
const adminId = String(body.admin_id || '').trim();
const instansi_id = String(body.instansi_id || '').trim();
const request_id = String(body.request_id || '').trim();

if (!id || !tgl || !jam || !jenis) {
  return [{ json: { ok: false, message: 'Data tidak lengkap (ID, Tanggal, Jam, Jenis wajib).' } }];
}

return [{ json: { ok: true, ID_Log: logId, telegram_id: id, nama, nip, tanggal: tgl, jam, jenis_absen: jenis, keterangan: ket, admin_id: adminId, request_id:request_id, instansi_id:instansi_id } }];

const rows = $input.all().map(i => {
  const p = i.json;

  // Normalisasi property agar dashboard tidak bingung dengan kapitalisasi
  const normalized = {
    ...p,
    id: String(p.id || ''),
    nama: p.username || '', // Di skema Anda 'username' sepertinya berisi nama lengkap
    nip: p.NIP || '',
    jabatan: p.Jabatan || '',
    status: p.Status || 'AKTIF'
  };

  // Logika pemetaan role dinamis
  const role = (function(p){ 
    const j = String(p.jabatan || '').toLowerCase(); 
    const r = String(p.role || '').toUpperCase(); 
    if (r && r !== 'USER') return r; 
    if (j.includes('kepala badan') || j.includes('kepala dinas')) return 'KEPALA'; 
    if (j.includes('sekretaris')) return 'SEKRETARIS'; 
    if (j.includes('kepala bidang') || j.includes('kabid')) return 'KABID'; 
    if (j.includes('irban')) return 'IRBAN'; 
    if (j.includes('inspektur')) return 'INSPEKTUR';
    return r || 'USER'; 
  })(normalized);

  return { ...normalized, role };
});

// Hanya kirim yang benar-benar admin/pimpinan
const admins = rows.filter(r => 
  ['ADMIN', 'SUPERADMIN', 'KEPALA', 'SEKRETARIS', 'KABID', 'IRBAN', 'INSPEKTUR'].includes(r.role) 
  || r.is_admin === true
);

return [{
  json: {
    ok: true,
    data: admins,
    total: admins.length,
    timestamp: new Date().toISOString()
  }
}];
